import React, { useEffect, useState } from 'react';
import api from '../utils/api';

const Orders = () => {
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/orders/my')
      .then((res) => { setOrders(res.data); setLoading(false); })
      .catch(() => setLoading(false));
  }, []);

  if (loading) return (
    <p style={{ textAlign: 'center', marginTop: '40px' }}>Loading orders...</p>
  );

  return (
    <div style={{ padding: '30px', maxWidth: '800px', margin: '0 auto' }}>
      <h2>📋 My Orders</h2>
      {orders.length === 0 && <p>You have no orders yet.</p>}
      {orders.map((order) => (
        <div key={order._id} style={styles.card}>
          <div style={{ display: 'flex', justifyContent: 'space-between' }}>
            <span><strong>Order ID:</strong> #{order._id.slice(-8)}</span>
            <span style={styles.status(order.status)}>
              {order.status.toUpperCase()}
            </span>
          </div>
          <p>Total: <strong>${order.totalPrice.toFixed(2)}</strong></p>
          <p>Date: {new Date(order.createdAt).toLocaleDateString()}</p>
          <div>
            {order.items.map((item, i) => (
              <p key={i} style={{ color: '#555', fontSize: '14px' }}>
                • {item.name} × {item.quantity}
              </p>
            ))}
          </div>
        </div>
      ))}
    </div>
  );
};

const styles = {
  card: { border: '1px solid #eee', borderRadius: '10px', padding: '16px', marginBottom: '16px', background: '#fff', boxShadow: '0 2px 8px rgba(0,0,0,0.05)' },
  status: (s) => ({
    padding: '4px 12px', borderRadius: '20px', fontSize: '13px',
    background: s === 'delivered' ? '#4caf50' : s === 'cancelled' ? '#f44336' : '#ff9800',
    color: '#fff',
  }),
};

export default Orders;
